def _prompt_manual_path():
    'Prompt for a manual ofscraper package path. Returns (method_guess, path_str).'
    print()
    print("Enter the path to your ofscraper package directory")
    print("(the folder containing __main__.py):")

    for attempt in range(3):
        raw = input("> ").strip().strip('"').strip("'")
        if not raw:
            print("No path entered. Please try again.")
            continue

        p = Path(raw).resolve()
        if not p.exists():
            print(f"Path does not exist: {p}")
            if attempt < 2:
                print("Please try again.")
            continue
        if not p.is_dir():
            print(f"Path is not a directory: {p}")
            if attempt < 2:
                print("Please try again.")
            continue
        if not (p / "__main__.py").is_file():
            print(f"Directory does not contain __main__.py: {p}")
            print("Make sure this is the ofscraper package directory (e.g. .../site-packages/ofscraper).")
            if attempt < 2:
                print("Please try again.")
            continue

        path_lower = str(p).lower()
        if "pipx" in path_lower:
            method = "pipx"
        elif "uv" in path_lower and "tools" in path_lower:
            method = "uv"
        else:
            method = "pip"

        print(f"Path verified: {p}")
        return (method, str(p))

    print("ERROR: Could not validate path after 3 attempts.")
    return ("exit", None)


def _get_installed_ofscraper_version() -> str | None:
    'Return the installed ofscraper version string, or None if not found.'
    try:
        import importlib.metadata
        return importlib.metadata.version("ofscraper")
    except Exception:
        pass
    try:
        result = subprocess.run(
            ["ofscraper", "--version"],
            capture_output=True, text=True, timeout=10,
        )
        for line in result.stdout.splitlines() + result.stderr.splitlines():
            line = line.strip()
            if line and any(c.isdigit() for c in line):
                m = _re.search(r'(\d+\.\d+\.\d+)', line)
                if m:
                    return m.group(1)
    except Exception:
        pass
    return None


def _version_tuple(v: str) -> tuple:
    try:
        return tuple(int(x) for x in v.split("."))
    except Exception:
        return (0, 0, 0)


def _check_and_offer_upgrade(method: str) -> bool:
    'Check installed ofscraper version; if < 3.14.3, offer to upgrade. Returns False to abort.'
    installed = _get_installed_ofscraper_version()
    if installed is None:
        print("Could not determine installed ofscraper version.")
        return True
    if _version_tuple(installed) >= _version_tuple("3.14.3"):
        print(f"Installed ofscraper version: {installed} (OK)")
        return True
    print()
    print(f"Installed ofscraper version: {installed}")
    print("This patch is designed for ofscraper 3.14.3.")
    print("Applying it to an older version may not work correctly.")
    print()
    while True:
        answer = input("Upgrade ofscraper to 3.14.3 now? (yes/no): ").strip().lower()
        if answer in ("yes", "y"):
            if not _install_ofscraper(method):
                print("Upgrade failed. Continuing with current version...")
            break
        if answer in ("no", "n"):
            while True:
                ans2 = input("Continue patching without upgrading? (yes/no): ").strip().lower()
                if ans2 in ("yes", "y"):
                    return True
                if ans2 in ("no", "n"):
                    print("Aborted.")
                    return False
                print("Please enter 'yes' or 'no'.")
            break
        print("Please enter 'yes' or 'no'.")
    return True


def _backup_files(target_pkg: Path, backup_root: Path, rel_paths: list[str]) -> None:
    for rel in rel_paths:
        dst = backup_root / rel
        src = target_pkg / rel
        dst.parent.mkdir(parents=True, exist_ok=True)
        if src.exists():
            shutil.copy2(src, dst)


def _apply_zip(target_pkg: Path, zip_bytes: bytes, *, dry_run: bool = False) -> None:
    zf = zipfile.ZipFile(io.BytesIO(zip_bytes), "r")
    for name in zf.namelist():
        if name.startswith("/") or name.startswith("\\") or ".." in Path(name).parts:
            raise RuntimeError(f"Unsafe path in patch zip: {name!r}")
        out_path = target_pkg / name
        if dry_run:
            continue
        out_path.parent.mkdir(parents=True, exist_ok=True)
        with zf.open(name) as src, open(out_path, "wb") as dst:
            shutil.copyfileobj(src, dst)


def restore(backup_dir: Path, target_pkg: Path | None = None) -> None:
    target_pkg = target_pkg or _pick_site_packages_ofscraper_dir()
    backup_dir = Path(backup_dir).resolve()
    if not backup_dir.is_dir():
        raise SystemExit(f"Backup dir does not exist: {backup_dir}")
    for rel in FILES:
        src = backup_dir / rel
        if not src.exists():
            continue
        dst = target_pkg / rel
        dst.parent.mkdir(parents=True, exist_ok=True)
        shutil.copy2(src, dst)
    print(f"Restored {len(FILES)} file(s) into {target_pkg}")


def apply(*, target: str | None = None, backup_dir: str | None = None, dry_run: bool = False) -> int:
    try:
        target_pkg = Path(target).resolve() if target else _pick_site_packages_ofscraper_dir()
    except Exception as e:
        print(f"ERROR: could not locate installed ofscraper: {e}")
        return 2

    if not target_pkg.exists():
        print(f"ERROR: target package dir does not exist: {target_pkg}")
        return 2

    ts = _dt.datetime.now().strftime("%Y%m%d_%H%M%S")
    backup_root = Path(backup_dir).resolve() if backup_dir else Path(tempfile.gettempdir()) / f"ofscraper_patch_backup_{PATCH_ID}_{ts}"
    if not dry_run:
        backup_root.mkdir(parents=True, exist_ok=True)

    zip_bytes = base64.b64decode(ZIP_B64.encode("ascii"))

    print(f"Patch ID: {PATCH_ID}")
    print(f"Target:   {target_pkg}")
    print(f"Files:    {FILE_COUNT}")
    print(f"Dry-run:  {dry_run}")
    if not dry_run:
        print(f"Backup:   {backup_root}")

    try:
        _backup_files(target_pkg, backup_root, FILES)
        _apply_zip(target_pkg, zip_bytes, dry_run=dry_run)
    except PermissionError as e:
        print(f"ERROR: permission denied writing to {target_pkg}")
        print("Try running this script in an elevated terminal (Administrator).")
        print(f"Details: {e}")
        return 3
    except Exception as e:
        print(f"ERROR: patch failed: {e}")
        if not dry_run:
            print(f"You can restore from backup: {backup_root}")
        return 1

    if dry_run:
        print("Dry-run complete (no files written).")
    else:
        print("Patch applied successfully.")
        print(f'If you need to undo: run with --restore "{backup_root}"'  )
    return 0


def main() -> int:
    ap = argparse.ArgumentParser(
        description="Patch pip/pipx/uv-installed ofscraper 3.14.3 with GUI-enabled files (Windows & Linux).",
    )
    ap.add_argument("--target", help="Explicit path to installed ofscraper package dir (site-packages/ofscraper).")
    ap.add_argument("--backup-dir", help="Where to store backups (defaults to temp).")
    ap.add_argument("--dry-run", action="store_true", help="Print what would happen; don't write files.")
    ap.add_argument("--skip-pyqt6", action="store_true", help="Skip automatic PyQt6 installation.")
    ap.add_argument("-y", "--yes", action="store_true", help="Skip the confirmation warning prompt.")
    ap.add_argument("--restore", help="Restore from a given backup directory.")
    args = ap.parse_args()

    if args.restore:
        if not _confirm_warning(skip=args.yes):
            print("Aborted.")
            return 0
        restore(Path(args.restore), Path(args.target).resolve() if args.target else None)
        return 0

    if not _confirm_warning(skip=args.yes):
        print("Aborted.")
        return 0

    # Check Python version (ofscraper 3.14.3 requires Python >=3.11, <3.14)
    ver = sys.version_info
    print(f"Python version:  {ver.major}.{ver.minor}.{ver.micro}")
    if ver < (3, 11) or ver >= (3, 14):
        print()
        print("WARNING: Python {}.{}.{} detected.".format(ver.major, ver.minor, ver.micro))
        print("         OF-Scraper 3.14.3 and this GUI patch may not work correctly.")
        print("         Recommended Python version: 3.11.x or 3.12.x")
        print()
        while True:
            answer = input("Open browser to download Python 3.11.6? (yes/no): ").strip().lower()
            if answer in ("yes", "y"):
                import webbrowser
                webbrowser.open("https://www.python.org/downloads/release/python-3116/")
                print("Browser opened. Install Python 3.11.6, then re-run this script.")
                return 0
            if answer in ("no", "n"):
                break
            print("Please enter 'yes' or 'no'.")

        while True:
            answer = input("Continue anyway with Python {}.{}.{}? (yes/no): ".format(
                ver.major, ver.minor, ver.micro)).strip().lower()
            if answer in ("yes", "y"):
                break
            if answer in ("no", "n"):
                print("Aborted.")
                return 0
            print("Please enter 'yes' or 'no'.")
        print()

    # Detect platform and install method
    plat = platform.system()
    method = _detect_install_method()
    print(f"Platform:        {plat}")
    print(f"Install method:  {method}")
    print()

    if method == "unknown":
        choice_method, manual_path = _prompt_install_method()
        if choice_method == "exit":
            print("Aborted.")
            return 0
        if manual_path:
            args.target = manual_path
            method = choice_method
        else:
            if not _install_ofscraper(choice_method):
                return 5
            method = choice_method
            method_check = _detect_install_method()
            if method_check != "unknown":
                method = method_check
        print(f"Install method:  {method}")
        print()

    # Check installed ofscraper version and offer upgrade if < 3.14.3
    if not _check_and_offer_upgrade(method):
        return 0

    if not args.skip_pyqt6:
        if not _install_pyqt6(method):
            return 4

    result = apply(target=args.target, backup_dir=args.backup_dir, dry_run=args.dry_run)
    if result == 0 and not args.dry_run:
        print()
        while True:
            answer = input("Launch OF-Scraper GUI now? (ofscraper --gui) (yes/no): ").strip().lower()
            if answer in ("yes", "y"):
                import subprocess as _sp
                _sp.Popen([sys.executable, "-m", "ofscraper", "--gui"])
                print("Launching OF-Scraper GUI...")
                break
            if answer in ("no", "n"):
                break
            print("Please enter 'yes' or 'no'.")
    return result


if __name__ == "__main__":
    raise SystemExit(main())
